-- =====================================================================
-- R__dev_seed_legacy_data.sql  （開発用シード／repeatable）
--
-- 旧 baseball-market（PHP）の本番相当データを開発環境へ投入する。
-- _docs/database/bb_market.sql の INSERT のみを data-only で抽出したもの。
--
-- 重要:
--   * これは「開発専用」シード。db/seed ロケーションは dev のみ flyway.locations に
--     含める（本番 application-prod では db/migration のみとする）。
--   * repeatable のため、内容変更時に再実行される。再実行で重複キーにならないよう
--     先頭で対象テーブルを全削除してから再投入する（FK チェックは一時的に無効化）。
--   * email/password は開発用に匿名化・統一している。email は user{id}@example.com 形式、
--     password は全ユーザー共通で平文 'password'（BCrypt ハッシュ）。
--     旧 users は email に UNIQUE が無く id=7 と id=52 が同一メールだったが、id ベースの
--     命名なので新スキーマの uk_users_email 制約に抵触しない。
--   * email_verification_tokens は旧ダンプにデータが無いため投入しない。
--   * products id=237（UNDER ARMOUR スパイク）は旧ダンプ時点で pic1〜pic3 が
--     存在しないファイル（5061db06…/654e59c8…/35df7466….jpeg）を指しており画像が
--     404 になる旧データ不整合があった。開発シードでは pic1 を実在する
--     uploads/descent_spike.jpg に差し替え、pic2/pic3 は空にしている
--     （_docs/database/bb_market.sql は旧本番の忠実なスナップショットとして未修正）。
--   * シードが参照する画像 fixture は db/seed/uploads/ に配置・コミットしている
--     （正規置き場）。配信は /uploads/** リソースハンドラ（WebConfig）が
--     classpath:/db/seed/uploads/ から解決する。static/uploads/ はランタイムの
--     ユーザーアップロード保存先（Git 非追跡）。
-- =====================================================================

SET FOREIGN_KEY_CHECKS = 0;

DELETE FROM `messages`;
DELETE FROM `boards`;
DELETE FROM `likes`;
DELETE FROM `email_verification_tokens`;
DELETE FROM `products`;
DELETE FROM `user_profiles`;
DELETE FROM `users`;
DELETE FROM `makers`;
DELETE FROM `categories`;

-- --- users ---
-- id=7 は退会済み(delete_flg=1)。開発用に email を user{id} 形式へ統一（id ベースなので衝突しない）
(7, 'user7@example.com', '$2y$10$7sf7lbEsIp2gmrdIkwZqneCzqUxycf13SuM45Ps5R6.yW7y8SwM8O', 1, NULL, '2026-03-28 16:12:01', '2026-03-29 11:08:17', '2026-03-28 16:12:01'),
(52, 'user52@example.com', '$2y$10$7sf7lbEsIp2gmrdIkwZqneCzqUxycf13SuM45Ps5R6.yW7y8SwM8O', 0, NULL, '2026-03-29 11:09:23', '2026-03-29 11:10:38', '2026-03-29 11:10:38');

